</div>
<script>
(function() {
    var remaining = {{ locked_seconds }};
    var timer = document.getElementById('lockout-timer');
    var interval = setInterval(function() {
        remaining--;
        if (remaining <= 0) {
            clearInterval(interval);
            document.getElementById('lockout-msg').style.display = 'none';
        } else {
            var m = Math.floor(remaining / 60);
            var s = remaining % 60;
            timer.textContent = (m > 0 ? m + 'm ' : '') + s + 's';
        }
    }, 1000);
})();
</script>
