                "moderate_rules": [
                    "PHQ-9 >= 10", "GAD-7 >= 10", "BP = Stage 1 or Stage 2",
                    "Fall risk >= 1 flag", "Medication: sometimes or often miss"
                ],
            }),
        )
        db_session.add(template)
        db_session.commit()
    return template

