<div class="card auth-container">
    <div class="auth-card card">
        <h2>Confirm Appointment</h2>
        <p><strong>Date:</strong> {{ slot.date }}</p>
        <p><strong>Time:</strong> {{ slot.start_time.strftime('%H:%M') }} — {{ slot.end_time.strftime('%H:%M') }}</p>
        <p><strong>Clinician:</strong> {{ slot.clinician.user.username }}</p>

        {% if remaining_seconds > 0 %}
        <div class="alert alert-warning" id="hold-timer">
            Hold expires in <span id="countdown">{{ remaining_seconds }}</span> seconds
        </div>
        <script>
        (function(){
            var r={{ remaining_seconds }};
            var el=document.getElementById('countdown');
            setInterval(function(){
                r--;
                if(r<=0){el.textContent='0';document.getElementById('hold-timer').innerHTML='Hold expired. Please try again.';}
                else{var m=Math.floor(r/60),s=r%60;el.textContent=(m>0?m+'m ':'')+s+'s';}
            },1000);
        })();
        </script>
        {% endif %}

        <form method="POST" style="margin-top:1rem;">
            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
            <button type="submit" class="btn btn-primary btn-block">Confirm Booking</button>
