        <form method="POST" action="{{ url_for('schedule.cancel', reservation_id=reservation.id) }}" style="margin-top:0.5rem;">
            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
            <button type="submit" class="btn btn-secondary btn-block">Cancel</button>
        </form>
    </div>
</div>
{% endblock %}

